function calculate({ regionGDP, baselineEnergyCostShare, fossilFuelDependency, policyAdherenceLevel, greenInvestmentCapacity, industryCarbonIntensityIndex, techAdoptionRate }) {

  // Input validation and normalization
  regionGDP = Math.max(0, regionGDP);
  baselineEnergyCostShare = Math.min(Math.max(0, baselineEnergyCostShare), 100) / 100;
  fossilFuelDependency = Math.min(Math.max(0, fossilFuelDependency), 100) / 100;
  policyAdherenceLevel = Math.min(Math.max(0, policyAdherenceLevel), 100) / 100;
  greenInvestmentCapacity = Math.max(0, greenInvestmentCapacity);
  industryCarbonIntensityIndex = Math.min(Math.max(0, industryCarbonIntensityIndex), 10) / 10; // Normalize to 0-1
  techAdoptionRate = Math.min(Math.max(0, techAdoptionRate), 100) / 100;

  // --- Constants and Assumptions ---
  const BASE_ENERGY_EFFICIENCY_GAIN = 0.005; // Base annual energy efficiency gain without policy change
  const POLICY_DRIVEN_EFFICIENCY_BOOST = 0.01; // Additional efficiency gain for high adherence
  const RENEWABLE_COST_REDUCTION_RATE = 0.03; // Assumed annual cost reduction for renewables
  const CARBON_PENALTY_RATE = 0.0005; // Base penalty per % fossil fuel dependency * % deviation
  const GREEN_INVESTMENT_MULTIPLIER = 1.8; // Multiplier for economic return on green investments
  const JOB_CREATION_PER_BILLION_USD_GREEN = 7500; // Jobs created per billion USD in green sector
  const INDUSTRY_TRANSITION_RISK_FACTOR = 0.002; // Base factor for industry transition costs related to carbon intensity
  const DEVIATION_TARIFF_FACTOR = 0.0008; // Factor for external tariffs/penalties due to policy deviation

  // --- Step 1: Calculate Energy Cost Impact ---
  // Policy alignment effect on energy costs: High adherence leads to lower long-term costs (efficiency, renewables).
  // Deviation leads to higher costs (carbon pricing, less efficient systems, potential tariffs).
  let effectiveEfficiencyGain = BASE_ENERGY_EFFICIENCY_GAIN + (policyAdherenceLevel * POLICY_DRIVEN_EFFICIENCY_BOOST);
  let renewableShiftBenefit = (1 - fossilFuelDependency) * policyAdherenceLevel * RENEWABLE_COST_REDUCTION_RATE;
  let fossilFuelCostPenalty = fossilFuelDependency * (1 - policyAdherenceLevel) * CARBON_PENALTY_RATE;

  let energyCostChangeRate = (renewableShiftBenefit - fossilFuelCostPenalty - effectiveEfficiencyGain);

  // Cap energy cost change to avoid extreme values
  energyCostChangeRate = Math.min(Math.max(energyCostChangeRate, -0.05), 0.05); // Cap between -5% and +5%

  const currentEnergyCost = regionGDP * baselineEnergyCostShare;
  const energyCostChange = -currentEnergyCost * energyCostChangeRate; // Negative rate means cost reduction, positive rate means cost increase

  // --- Step 2: Estimate Green Investment Return ---
  // Green investment return is boosted by policy adherence and technology adoption.
  let effectiveGreenInvestment = greenInvestmentCapacity * (1 + policyAdherenceLevel * 0.5) * techAdoptionRate;
  const greenInvestmentReturn = effectiveGreenInvestment * GREEN_INVESTMENT_MULTIPLIER;

  // --- Step 3: Calculate Industry Transition Cost/Penalty ---
  // Industries with high carbon intensity face higher transition costs or penalties if policy adherence is low.
  // Conversely, high adherence might lead to costs but also subsidies/support that net out or provide future gains.
  let directIndustryCostFactor = industryCarbonIntensityIndex * (1 - policyAdherenceLevel) * INDUSTRY_TRANSITION_RISK_FACTOR;
  let externalDeviationPenalty = regionGDP * (1 - policyAdherenceLevel) * DEVIATION_TARIFF_FACTOR;

  const industryTransitionCost = (regionGDP * directIndustryCostFactor) + externalDeviationPenalty;

  // --- Step 4: Aggregate GDP Impact ---
  const netGDPImpact = greenInvestmentReturn - industryTransitionCost + energyCostChange;

  // --- Step 5: Estimate Job Impact ---
  // Job impact is primarily driven by green investments and net GDP changes.
  // Positive green investments create jobs, negative industry impacts may lose jobs.
  let jobsFromGreenInvestment = greenInvestmentCapacity * JOB_CREATION_PER_BILLION_USD_GREEN * techAdoptionRate; // Use initial capacity to avoid double counting multiplier
  let jobsLostFromTransition = (industryTransitionCost > 0 ? (industryTransitionCost / 1000) * (JOB_CREATION_PER_BILLION_USD_GREEN / 2) : 0); // Simplified loss rate

  const jobImpact = jobsFromGreenInvestment - jobsLostFromTransition;

  return {
    netGDPImpact: netGDPImpact,
    energyCostChange: energyCostChange,
    greenInvestmentReturn: greenInvestmentReturn,
    industryTransitionCost: industryTransitionCost,
    jobImpact: Math.round(jobImpact)
  };
}
